        let mut fb = vec![0u32; 400]; // 20x20
        fill_circle(&mut fb, 20, 20, -100, -100, 10, 0xFF_FF_00_00);
        fill_circle(&mut fb, 20, 20, 10, 10, -5, 0xFF_FF_00_00);
