/// Profundidad máxima del quadtree (4 niveles = 256 celdas hoja)
const MAX_DEPTH: u8 = 6;
/// Máximo de entidades por nodo antes de subdividir
const MAX_ENTITIES_PER_NODE: usize = 16;
/// Capacidad máxima de entidades en todo el quadtree
const MAX_TOTAL_ENTITIES: usize = 16384;

/// Índice de entidad en el quadtree
#[derive(Copy, Clone, Debug, PartialEq, Eq)]
pub struct QuadEntity(u32);

impl QuadEntity {
    pub const INVALID: Self = QuadEntity(u32::MAX);

    #[inline(always)]
    pub fn index(self) -> usize {
        self.0 as usize
    }

    #[inline(always)]
