    #[inline(always)]
    pub fn is_key_pressed(&self, key: GameKey) -> bool {
        (self.keys_pressed & (1u128 << (key as u8))) != 0
    }

    /// Tecla recién soltada en este frame (flanco)
    #[inline(always)]
    pub fn is_key_released(&self, key: GameKey) -> bool {
        (self.keys_released & (1u128 << (key as u8))) != 0
    }
